import { existsSync, readFileSync, writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import path from 'node:path';

const scriptDir = path.dirname(fileURLToPath(import.meta.url));
const repoRoot = path.resolve(scriptDir, '../..');
const metricsOutputPath = path.join(
  repoRoot,
  'WebApp',
  'src',
  'app',
  'shared',
  'data',
  'github-metrics.ts',
);

const USERNAME = process.env.GITHUB_USERNAME || 'khaneliman';
const GITHUB_TOKEN = process.env.GH_TOKEN || process.env.GITHUB_TOKEN;
const REPRESENTED_REPOS = [
  { query: 'NixOS/nixpkgs', metricsRepoName: 'Nixpkgs' },
  { query: 'nix-community/home-manager', metricsRepoName: 'Home Manager' },
  { query: 'nix-community/nixvim', metricsRepoName: 'Nixvim' },
  { query: 'Alexays/Waybar', metricsRepoName: 'Waybar' },
];

const METRICS_SHAPE_REGEX = /repo:\s*['"]([^'"]+)['"]\s*,\s*mergedPrs:\s*(\d+)/g;

async function getMergedPrCount(repo) {
  const query = `repo:${repo} author:${USERNAME} is:pr is:merged`;
  const url = `https://api.github.com/search/issues?q=${encodeURIComponent(query)}&per_page=1`;
  const headers = {
    Accept: 'application/vnd.github+json',
    'User-Agent': `github-metrics-bot/${USERNAME}`,
    'X-GitHub-Api-Version': '2022-11-28',
  };

  if (GITHUB_TOKEN) {
    headers.Authorization = `Bearer ${GITHUB_TOKEN}`;
  }

  const response = await fetch(url, { headers });
  if (!response.ok) {
    const body = await response.json().catch(() => ({}));
    const message = body.message || 'Unknown error';
    throw new Error(`Failed to fetch metrics for ${repo}: ${response.status} ${response.statusText} (${message})`);
  }

  const payload = await response.json();
  return payload.total_count ?? 0;
}

function formatMetricDate(date) {
  return date.toISOString().slice(0, 10);
}

function createMetricsFile({ asOf, repoCounts, totalMergedPrs }) {
  const repoMetricsLines = REPRESENTED_REPOS.map(
    (target) => `    { repo: '${target.metricsRepoName}', mergedPrs: ${repoCounts[target.metricsRepoName]} },`,
  ).join('\n');

  return `// This file is generated by .github/scripts/update-github-metrics.mjs
// and should be updated via the GitHub Action.

export interface RepoContributionMetrics {
  repo: string;
  mergedPrs: number;
}

export interface GitHubMetrics {
  asOf: string;
  totalMergedPrs: number;
  repoMetrics: RepoContributionMetrics[];
}

export const GITHUB_METRICS: GitHubMetrics = {
  asOf: '${asOf}',
  totalMergedPrs: ${totalMergedPrs},
  repoMetrics: [
${repoMetricsLines}
  ],
};
`;
}

async function main() {
  const repoCounts = Object.fromEntries(
    await Promise.all(
      REPRESENTED_REPOS.map(async (target) => [target.metricsRepoName, await getMergedPrCount(target.query)]),
    ),
  );
  const existingRepoCounts = readExistingRepoCounts();

  if (!hasMetricChanges(existingRepoCounts, repoCounts)) {
    return;
  }

  const asOf = formatMetricDate(new Date());
  const totalMergedPrs = Object.values(repoCounts).reduce((total, count) => total + count, 0);
  const contents = createMetricsFile({ asOf, repoCounts, totalMergedPrs });

  writeFileSync(metricsOutputPath, contents, 'utf8');
  console.log(`Updated ${path.relative(repoRoot, metricsOutputPath)} to counts ${JSON.stringify(repoCounts)} on ${asOf}`);
}

function readExistingRepoCounts() {
  if (!existsSync(metricsOutputPath)) {
    return null;
  }

  const existingMetricsFile = readFileSync(metricsOutputPath, 'utf8');
  const parsedMetrics = [...existingMetricsFile.matchAll(METRICS_SHAPE_REGEX)];
  if (!parsedMetrics.length) {
    return null;
  }

  const counts = parsedMetrics.reduce((acc, match) => {
    acc[match[1]] = Number(match[2]);
    return acc;
  }, {});

  return hasValidCounts(counts) ? counts : null;
}

function hasMetricChanges(previousRepoCounts, newRepoCounts) {
  if (previousRepoCounts === null) {
    return true;
  }

  const increasedRepos = REPRESENTED_REPOS.filter((target) => {
    const previousCount = previousRepoCounts[target.metricsRepoName];
    const newCount = newRepoCounts[target.metricsRepoName];

    return (
      Number.isFinite(previousCount) &&
      Number.isFinite(newCount) &&
      newCount > previousCount
    );
  });

  if (!increasedRepos.length) {
    console.log('No represented repo PR count increases detected. Skipping metrics file update.');
    return false;
  }

  return true;
}

function hasValidCounts(existingRepoCounts) {
  return REPRESENTED_REPOS.every((target) => Number.isFinite(existingRepoCounts[target.metricsRepoName]));
}

main().catch((error) => {
  console.error(error.message);
  process.exit(1);
});
